import { DefaultAzureCredential } from '@azure/identity';
import { ResourceManagementClient } from '@azure/arm-resources';
import { BlobServiceClient } from '@azure/storage-blob';

const credential = new DefaultAzureCredential();
const subscriptionId = process.env.AZURE_SUBSCRIPTION_ID!;

// Management plane: list resource groups
const resourceClient = new ResourceManagementClient(credential, subscriptionId);

async function listResourceGroups() {
    for await (const rg of resourceClient.resourceGroups.list()) {
        console.log(rg.name, rg.location);
    }
}

// Data plane: upload a blob
async function uploadBlob(containerName: string, blobName: string, content: string) {
    const blobService = new BlobServiceClient(
        'https://mystorageaccount.blob.core.windows.net',
        credential
    );
    const container = blobService.getContainerClient(containerName);
    await container.uploadBlockBlob(blobName, content, Buffer.byteLength(content));
    console.log(`Uploaded ${blobName}`);
}

// Long-running operation: start a VM
async function startVM(rg: string, vmName: string) {
    const { ComputeManagementClient } = await import('@azure/arm-compute');
    const computeClient = new ComputeManagementClient(credential, subscriptionId);
    const poller = await computeClient.virtualMachines.beginStart(rg, vmName);
    await poller.pollUntilDone();  // waits for completion
    console.log('VM started');
}

