package main

import (
    "context"
    "fmt"
    "os"

    "github.com/Azure/azure-sdk-for-go/sdk/azcore/to"
    "github.com/Azure/azure-sdk-for-go/sdk/azidentity"
    "github.com/Azure/azure-sdk-for-go/sdk/resourcemanager/resources/armresources"
)

func main() {
    subscriptionID := os.Getenv("AZURE_SUBSCRIPTION_ID")
    ctx := context.Background()

    // DefaultAzureCredential — same auth chain as other languages
    cred, err := azidentity.NewDefaultAzureCredential(nil)
    if err != nil {
        panic(err)
    }

    // Create a resource group client
    rgClient, err := armresources.NewResourceGroupsClient(subscriptionID, cred, nil)
    if err != nil {
        panic(err)
    }

    // Create a resource group
    resp, err := rgClient.CreateOrUpdate(ctx, "myRG", armresources.ResourceGroup{
        Location: to.Ptr("eastus"),
        Tags:     map[string]*string{"env": to.Ptr("prod")},
    }, nil)
    if err != nil {
        panic(err)
    }
    fmt.Printf("Created: %s\n", *resp.Name)

    // List resource groups (pager)
    pager := rgClient.NewListPager(nil)
    for pager.More() {
        page, err := pager.NextPage(ctx)
        if err != nil {
            panic(err)
        }
        for _, rg := range page.Value {
            fmt.Printf("%s (%s)\n", *rg.Name, *rg.Location)
        }
    }
}

import unittest
from unittest.mock import MagicMock, patch
from azure.mgmt.resource import ResourceManagementClient

def ensure_resource_group(client, name: str, location: str) -> str:
    rg = client.resource_groups.create_or_update(name, {'location': location})
    return rg.name

class TestResourceGroup(unittest.TestCase):
    def test_ensure_resource_group(self):
        # Mock the client and response
        mock_client = MagicMock(spec=ResourceManagementClient)
        mock_rg = MagicMock()
        mock_rg.name = 'myRG'
        mock_client.resource_groups.create_or_update.return_value = mock_rg

        result = ensure_resource_group(mock_client, 'myRG', 'eastus')

        self.assertEqual(result, 'myRG')
        mock_client.resource_groups.create_or_update.assert_called_once_with(
            'myRG', {'location': 'eastus'}
        )

if __name__ == '__main__':
    unittest.main()

