import { getVMPowerState } from './vm-service';

test('returns VM power state', async () => {
    const mockClient = {
        virtualMachines: {
            instanceView: jest.fn().mockResolvedValue({
                statuses: [
                    { code: 'ProvisioningState/succeeded', displayStatus: 'Provisioning succeeded' },
                    { code: 'PowerState/running', displayStatus: 'VM running' },
                ],
            }),
        },
    } as any;

    const state = await getVMPowerState(mockClient, 'myRG', 'myVM');
    expect(state).toBe('VM running');
});

